import json
import boto3
import os
from datetime import datetime
from typing import Dict, Any, List, Optional

sns_client = boto3.client('sns')

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Lambda function to publish messages to SNS topics.
    
    Event structure:
    {
        "topic_arn": "arn:aws:sns:region:account:topic-name",
        "message": "Message content",
        "subject": "Optional subject",
        "notification_type": "email|sms|application|all",
        "message_attributes": {
            "key": "value"
        },
        "batch_messages": [
            {
                "topic_arn": "arn",
                "message": "content",
                "subject": "subject"
            }
        ]
    }
    """
    
    try:
        # Handle batch messages
        if 'batch_messages' in event and event['batch_messages']:
            return handle_batch_publish(event['batch_messages'])
        
        # Handle single message
        topic_arn = event.get('topic_arn')
        message = event.get('message')
        subject = event.get('subject', '')
        notification_type = event.get('notification_type', 'all')
        message_attributes = event.get('message_attributes', {})
        
        # Validate required fields
        if not topic_arn:
            return create_response(400, 'topic_arn is required')
        
        if not message:
            return create_response(400, 'message is required')
        
        # Publish based on notification type
        if notification_type == 'email':
            result = publish_email_notification(topic_arn, message, subject, message_attributes)
        elif notification_type == 'sms':
            result = publish_sms_notification(topic_arn, message, message_attributes)
        elif notification_type == 'application':
            result = publish_application_notification(topic_arn, message, message_attributes)
        elif notification_type == 'structured':
            result = publish_structured_message(topic_arn, message, subject, message_attributes)
        else:
            result = publish_standard_notification(topic_arn, message, subject, message_attributes)
        
        return create_response(200, 'Message published successfully', result)
        
    except Exception as e:
        print(f"Error publishing message: {str(e)}")
        return create_response(500, f'Error publishing message: {str(e)}')


def publish_standard_notification(topic_arn: str, message: str, subject: str, 
                                  attributes: Dict[str, Any]) -> Dict[str, Any]:
    """Publish a standard notification to SNS topic."""
    
    params = {
        'TopicArn': topic_arn,
        'Message': message
    }
    
    if subject:
        params['Subject'] = subject[:100]  # SNS subject limit is 100 characters
    
    if attributes:
        params['MessageAttributes'] = format_message_attributes(attributes)
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'standard'
    }


def publish_email_notification(topic_arn: str, message: str, subject: str,
                               attributes: Dict[str, Any]) -> Dict[str, Any]:
    """Publish an email notification with proper formatting."""
    
    # Add email-specific attributes
    email_attributes = attributes.copy()
    email_attributes['notification_type'] = 'email'
    email_attributes['timestamp'] = datetime.utcnow().isoformat()
    
    params = {
        'TopicArn': topic_arn,
        'Message': message,
        'Subject': subject[:100] if subject else 'Notification',
        'MessageAttributes': format_message_attributes(email_attributes)
    }
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'email',
        'subject': params['Subject']
    }


def publish_sms_notification(topic_arn: str, message: str, 
                            attributes: Dict[str, Any]) -> Dict[str, Any]:
    """Publish an SMS notification (limited to 140 characters)."""
    
    # Truncate message for SMS
    sms_message = message[:140]
    
    sms_attributes = attributes.copy()
    sms_attributes['notification_type'] = 'sms'
    sms_attributes['AWS.SNS.SMS.SMSType'] = 'Transactional'
    
    params = {
        'TopicArn': topic_arn,
        'Message': sms_message,
        'MessageAttributes': format_message_attributes(sms_attributes)
    }
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'sms',
        'message_length': len(sms_message)
    }


def publish_application_notification(topic_arn: str, message: str,
                                    attributes: Dict[str, Any]) -> Dict[str, Any]:
    """Publish a notification for mobile applications (JSON format)."""
    
    # Create platform-specific message structure
    if isinstance(message, str):
        try:
            message_data = json.loads(message)
        except json.JSONDecodeError:
            message_data = {'default': message}
    else:
        message_data = message
    
    # Structure for different platforms
    structured_message = {
        'default': message_data.get('default', 'New notification'),
        'GCM': json.dumps({
            'notification': {
                'title': message_data.get('title', 'Notification'),
                'body': message_data.get('body', message_data.get('default', '')),
                'sound': 'default'
            },
            'data': message_data.get('data', {})
        }),
        'APNS': json.dumps({
            'aps': {
                'alert': {
                    'title': message_data.get('title', 'Notification'),
                    'body': message_data.get('body', message_data.get('default', ''))
                },
                'sound': 'default',
                'badge': 1
            },
            'data': message_data.get('data', {})
        })
    }
    
    app_attributes = attributes.copy()
    app_attributes['notification_type'] = 'application'
    
    params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(structured_message),
        'MessageStructure': 'json',
        'MessageAttributes': format_message_attributes(app_attributes)
    }
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'application',
        'platforms': ['GCM', 'APNS']
    }


def publish_structured_message(topic_arn: str, message: str, subject: str,
                               attributes: Dict[str, Any]) -> Dict[str, Any]:
    """Publish a structured message with different content for different protocols."""
    
    if isinstance(message, str):
        try:
            message_structure = json.loads(message)
        except json.JSONDecodeError:
            message_structure = {
                'default': message,
                'email': message,
                'sms': message[:140]
            }
    else:
        message_structure = message
    
    # Ensure default message exists
    if 'default' not in message_structure:
        message_structure['default'] = str(message_structure.get('email', 
                                           message_structure.get('sms', 'Notification')))
    
    structured_attributes = attributes.copy()
    structured_attributes['notification_type'] = 'structured'
    
    params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(message_structure),
        'MessageStructure': 'json',
        'MessageAttributes': format_message_attributes(structured_attributes)
    }
    
    if subject:
        params['Subject'] = subject[:100]
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'structured',
        'protocols': list(message_structure.keys())
    }


def handle_batch_publish(batch_messages: List[Dict[str, Any]]) -> Dict[str, Any]:
    """Handle publishing multiple messages in batch."""
    
    results = []
    errors = []
    
    for idx, msg in enumerate(batch_messages):
        try:
            topic_arn = msg.get('topic_arn')
            message = msg.get('message')
            subject = msg.get('subject', '')
            notification_type = msg.get('notification_type', 'all')
            message_attributes = msg.get('message_attributes', {})
            
            if not topic_arn or not message:
                errors.append({
                    'index': idx,
                    'error': 'Missing topic_arn or message'
                })
                continue
            
            # Publish based on type
            if notification_type == 'email':
                result = publish_email_notification(topic_arn, message, subject, message_attributes)
            elif notification_type == 'sms':
                result = publish_sms_notification(topic_arn, message, message_attributes)
            elif notification_type == 'application':
                result = publish_application_notification(topic_arn, message, message_attributes)
            elif notification_type == 'structured':
                result = publish_structured_message(topic_arn, message, subject, message_attributes)
            else:
                result = publish_standard_notification(topic_arn, message, subject, message_attributes)
            
            results.append({
                'index': idx,
                'success': True,
                'result': result
            })
            
        except Exception as e:
            errors.append({
                'index': idx,
                'error': str(e)
            })
    
    return create_response(200 if not errors else 207, 'Batch publish completed', {
        'total': len(batch_messages),
        'successful': len(results),
        'failed': len(errors),
        'results': results,
        'errors': errors
    })


def format_message_attributes(attributes: Dict[str, Any]) -> Dict[str, Dict[str, str]]:
    """Format message attributes for SNS."""
    
    formatted_attributes = {}
    
    for key, value in attributes.items():
        if isinstance(value, str):
            formatted_attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, (int, float)):
            formatted_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        elif isinstance(value, list):
            formatted_attributes[key] = {
                'DataType': 'String.Array',
                'StringValue': json.dumps(value)
            }
        else:
            formatted_attributes[key] = {
                'DataType': 'String',
                'StringValue': json.dumps(value)
            }
    
    return formatted_attributes


def create_response(status_code: int, message: str, data: Any = None) -> Dict[str, Any]:
    """Create a standardized response."""
    
    response = {
        'statusCode': status_code,
        'body': json.dumps({
            'message': message,
            'timestamp': datetime.utcnow().isoformat(),
            'data': data
        })
    }
    
    return response


def publish_with_deduplication(topic_arn: str, message: str, 
                               deduplication_id: str, group_id: str = None) -> Dict[str, Any]:
    """Publish message with deduplication (for FIFO topics)."""
    
    params = {
        'TopicArn': topic_arn,
        'Message': message,
        'MessageDeduplicationId': deduplication_id
    }
    
    if group_id:
        params['MessageGroupId'] = group_id
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'deduplication_id': deduplication_id,
        'group_id': group_id
    }


